1	export type Item = {
2	  type: string;
3	  material?: string;
4	  cursed?: boolean;
5	  enchantment?: number;
6	};
7	
8	export type QuoteStep = { op: "quote"; items: Item[] };
9	
10	export type Damage = { itemType: string; amount: number };
11	export type Incident = { cause: string; damages: Damage[] };
12	export type ClaimStep = { op: "claim"; policy: number; incident: Incident };
13	
14	export type Step = QuoteStep | ClaimStep;
15	
16	export type Scenario = {
17	  customer: { yearsWithMHPCO: number };
18	  steps: Step[];
19	};
20	
21	export type QuoteResult = { premium: number };
22	export type ClaimResult = { payout: number; remainingCap: number };
23	export type StepResult = QuoteResult | ClaimResult;
24	
25	export type ScenarioResult = {
26	  results: StepResult[];
27	};
28	
29	const PROCESSING_FEE = 5;
30	const DEDUCTIBLE = 100;
31	const CAP_MULTIPLIER = 2;
32	
33	const BASE_PREMIUMS: Record<string, number> = {
34	  sword: 100,
35	  amulet: 60,
36	  staff: 80,
37	  potion: 40,
38	  rune: 25,
39	  moonstone: 25,
40	};
41	
42	const INSURANCE_VALUES: Record<string, number> = {
43	  sword: 1000,
44	  amulet: 600,
45	  staff: 800,
46	  potion: 400,
47	  rune: 250,
48	  moonstone: 250,
49	};
50	
51	const BLOCK_SIZE = 3;
52	const BLOCK_PRICE = 60;
53	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
54	
55	const LOYALTY_YEARS_THRESHOLD = 2;
56	const LOYALTY_DISCOUNT_RATE = 0.2;
57	const FIRST_INSURANCE_RATE = 0.1;
58	
59	const CURSE_SURCHARGE_RATE = 0.5;
60	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
61	const HIGH_ENCHANTMENT_THRESHOLD = 5;
62	const FOLLOWUP_DISCOUNT_RATE = 0.15;
63	
64	const unitPrice = (type: string): number => {
65	  const price = BASE_PREMIUMS[type];
66	  if (price === undefined) throw new Error(`Unknown item type: ${type}`);
67	  return price;
68	};
69	
70	const insuranceValue = (type: string): number => {
71	  const value = INSURANCE_VALUES[type];
72	  if (value === undefined) throw new Error(`Unknown item type: ${type}`);
73	  return value;
74	};
75	
76	const countBy = <T>(values: T[], key: (value: T) => string): Map<string, number> =>
77	  values.reduce(
78	    (counts, value) => counts.set(key(value), (counts.get(key(value)) ?? 0) + 1),
79	    new Map<string, number>()
80	  );
81	
82	const groupTotal = (type: string, count: number): number =>
83	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE
84	    ? BLOCK_PRICE
85	    : count * unitPrice(type);
86	
87	const sumBasePremiums = (items: Item[]): number =>
88	  Array.from(countBy(items, (item) => item.type)).reduce(
89	    (total, [type, count]) => total + groupTotal(type, count),
90	    0
91	  );
92	
93	const itemSurcharges = (item: Item): number => {
94	  const base = unitPrice(item.type);
95	  const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
96	  const enchantment = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
97	    ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
98	    : 0;
99	  return curse + enchantment;
100	};
101	
102	const sumItemSurcharges = (items: Item[]): number =>
103	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
104	
105	const loyaltyDiscount = (
106	  basePremiums: number,
107	  customer: { yearsWithMHPCO: number }
108	): number =>
109	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
110	    ? basePremiums * LOYALTY_DISCOUNT_RATE
111	    : 0;
112	
113	const followupDiscount = (basePremiums: number, quoteIndex: number): number =>
114	  quoteIndex > 0 ? basePremiums * FOLLOWUP_DISCOUNT_RATE : 0;
115	
116	const quote = (
117	  { items }: QuoteStep,
118	  customer: { yearsWithMHPCO: number },
119	  quoteIndex: number
120	): QuoteResult => {
121	  const basePremiums = sumBasePremiums(items);
122	  const raw =
123	    basePremiums +
124	    sumItemSurcharges(items) -
125	    loyaltyDiscount(basePremiums, customer) +
126	    basePremiums * FIRST_INSURANCE_RATE -
127	    followupDiscount(basePremiums, quoteIndex) +
128	    PROCESSING_FEE;
129	  return { premium: Math.ceil(raw) };
130	};
131	
132	type Policy = {
133	  items: Item[];
134	  cap: number;
135	  remainingCap: number;
136	};
137	
138	const createPolicy = (items: Item[]): Policy => {
139	  const insuranceSum = items.reduce(
140	    (sum, item) => sum + insuranceValue(item.type),
141	    0
142	  );
143	  const cap = insuranceSum * CAP_MULTIPLIER;
144	  return { items, cap, remainingCap: cap };
145	};
146	
147	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
148	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
149	
150	const reimbursableAmount = (damage: Damage, item: Item): number =>
151	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
152	    ? damage.amount * HIGH_ENCHANTMENT_PAYOUT_RATE
153	    : damage.amount;
154	
155	const damagePayout = (damage: Damage, item: Item): number =>
156	  Math.max(0, reimbursableAmount(damage, item) - DEDUCTIBLE);
157	
158	const sumDamagePayouts = (damages: Damage[], items: Item[]): number =>
159	  damages.reduce((sum, d) => {
160	    const item = items.find((i) => i.type === d.itemType);
161	    if (!item) throw new Error(`Item ${d.itemType} not in policy`);
162	    return sum + damagePayout(d, item);
163	  }, 0);
164	
165	const claim = (step: ClaimStep, policies: Map<number, Policy>): ClaimResult => {
166	  const policy = policies.get(step.policy);
167	  if (!policy) throw new Error(`Policy ${step.policy} not found`);
168	  for (const d of step.incident.damages) {
169	    if (d.amount < 0) throw new Error(`Damage amount cannot be negative: ${d.amount}`);
170	  }
171	  const damageCounts = countBy(step.incident.damages, (d) => d.itemType);
172	  const itemCounts = countBy(policy.items, (item) => item.type);
173	  for (const [type, count] of damageCounts) {
174	    if (count > (itemCounts.get(type) ?? 0)) {
175	      throw new Error(`Too many damages for item type ${type}`);
176	    }
177	  }
178	  const desired = sumDamagePayouts(step.incident.damages, policy.items);
179	  const payout = Math.min(desired, policy.remainingCap);
180	  policy.remainingCap -= payout;
181	  return { payout: Math.floor(payout), remainingCap: policy.remainingCap };
182	};
183	
184	export const runScenario = (scenario: Scenario): ScenarioResult => {
185	  const policies = new Map<number, Policy>();
186	  let quoteIndex = 0;
187	  const results: StepResult[] = scenario.steps.map((step, index) => {
188	    if (step.op === "quote") {
189	      policies.set(index, createPolicy(step.items));
190	      const result = quote(step, scenario.customer, quoteIndex);
191	      quoteIndex++;
192	      return result;
193	    }
194	    return claim(step, policies);
195	  });
196	  return { results };
197	};
